sap.ui.define(["sap/ui/core/mvc/Controller"],function(e){"use strict";return e.extend("curriculo.project1.controller.View1",{onInit:function(){this.byId("_IDGenSwitch").setState(true);this.onChangeLanguage({getParameter:()=>true})},onChangeLanguage:function(e){const n=new Date(2022,11);const t=new Date;let o=(t.getFullYear()-n.getFullYear())*12;o+=t.getMonth()-n.getMonth();const i=Math.floor(o/12);const s=o%12;let a=this.getOwnerComponent().getModel("i18n").getResourceBundle();let r=e.getParameter("state");if(r){this.byId("_IDGenTitle").setText(a.getText("titulo_en"));this.byId("_IDGenLabel").setText(a.getText("idioma_en"));this.byId("_IDGenIconTabFilter").setText(a.getText("resumo_en"));this.byId("_IDGenIconTabFilter1").setText(a.getText("experiencia_en"));this.byId("_IDGenIconTabFilter2").setText(a.getText("formacao_en"));this.byId("_IDGenIconTabFilter3").setText(a.getText("contatos_en"));this.byId("_IDGenText").setText("By Carlos Queiroz | SAP ABAP & Fiori Developer");this.byId("_IDGenGroupElement").setLabel("Profile");this.byId("_IDGenGroupElement1").setLabel("SAP Experience – Summary");this.byId("_IDGenGroupElement2").setLabel("General Information");this.byId("_IDGenText2").setText(`SAP ABAP & Fiori Developer with ${i} year${i!==1?"s":""} and ${s} month${s!==1?"s":""} of hands-on experience in SAP ECC and S/4HANA environments. Proven track record across AMS, improvement projects, and full implementation cycles — from requirements gathering through go-live and post-production support.`);this.byId("_IDGenText3").setText(`• Development in projects such as Accounting Reconciliation Cockpit and system migration extractors\n• ABAP development: ALV, Smartforms (PDFs), ABAP OO, Module Pool, SAPScript\n• Creation of views and update clusters\n• Queries built via Eclipse\n• Implementation of BAPIs, BADIs, BTEs, User Exits, Enhancements, and PI Proxy\n• Advanced SELECTs with joins and program performance analysis\n• Creation of CDS Views and Fiori Apps consuming CDS\n• Fiori adaptation (Fiorization) of standard SAP transactions\n• Knowledge of tables: FI, SD, MM, PP, EWM, and Guepardo Tax\n• Debugging and adjustments in standard SAP processes\n• Development of Fiori Freestyle and Fiori Elements applications`);this.byId("_IDGenText5").setText(`Date of Birth:       21.11.2005\n────────────────────────────────────────────────────────────────────\nCitizenship:         Brazilian\n────────────────────────────────────────────────────────────────────\nResidence:           Pomerode – SC, Brazil\n────────────────────────────────────────────────────────────────────\nMobility:            National and International\n────────────────────────────────────────────────────────────────────\nMarital Status:      Single\n────────────────────────────────────────────────────────────────────\nLanguages:           Portuguese – Native | English – Intermediate B2 (studying toward C2)\n────────────────────────────────────────────────────────────────────`);this.byId("_IDGenLabel1").setText("Professional Experience – Summary");this.byId("_IDGenLabel2").setText("SAP Project Experience – Details");this.byId("_IDGenText1").setText(`Active across all project phases: requirements gathering, analysis, development, functional testing, and UAT approval.\n\n• Glatz – Current consulting firm\n• DFSpro IT Solutions\n• Clients served: Kyly, Usina Coruripe, Sotreq, Unimed, Destro, Agrícola Alvorada, Grupo Bom Jesus, Arke, and others\n• ABAP technical development and SAP system integration\n• Active participation in delivery of technical specs, testing cycles, improvements, and post-go-live support`);this.byId("_IDGenText4").setText(`Company:         Sotreq\n────────────────────────────────────────────────────────────────────\nDuration:         8 months\n────────────────────────────────────────────────────────────────────\nIndustry:         Caterpillar Machinery and Equipment\n────────────────────────────────────────────────────────────────────\nProject:          Accounting Reconciliation Cockpit\n────────────────────────────────────────────────────────────────────\nRole:             SAP ABAP Consultant\n────────────────────────────────────────────────────────────────────\n\nDevelopment of a solution for analysis, reconciliation, and clearing of accounting accounts — identifying process inconsistencies and performing individualized adjustments for proper account clearing.\n\n\nCompany:         Kyly\n────────────────────────────────────────────────────────────────────\nDuration:         Ongoing (current)\n────────────────────────────────────────────────────────────────────\nIndustry:         Textile\n────────────────────────────────────────────────────────────────────\nProject:          SAP S/4HANA Implementation\n────────────────────────────────────────────────────────────────────\nRole:             SAP ABAP/Fiori Consultant\n────────────────────────────────────────────────────────────────────\n\nActive participation in the SAP S/4HANA implementation project, focused on developing Fiori applications (Freestyle and Elements) and customizing standard processes through ABAP enhancements and adaptations.`);this.byId("_IDGenText8").setText(`• High School – Completed\n• Systems Analysis and Development – In progress (Higher Education)\n• SAP courses and training: ABAP, CDS Views, Fiori, SAP CAP, S/4HANA`)}else{this.byId("_IDGenTitle").setText(a.getText("titulo_pt"));this.byId("_IDGenLabel").setText(a.getText("idioma_pt"));this.byId("_IDGenIconTabFilter").setText(a.getText("resumo_pt"));this.byId("_IDGenIconTabFilter1").setText(a.getText("experiencia_pt"));this.byId("_IDGenIconTabFilter2").setText(a.getText("formacao_pt"));this.byId("_IDGenIconTabFilter3").setText(a.getText("contatos_pt"));this.byId("_IDGenText").setText("Feito por Carlos Queiroz | Desenvolvedor SAP ABAP & Fiori");this.byId("_IDGenGroupElement").setLabel("Perfil");this.byId("_IDGenGroupElement1").setLabel("Experiência SAP – Sumário");this.byId("_IDGenGroupElement2").setLabel("Informações Gerais");this.byId("_IDGenText2").setText(`Desenvolvedor SAP ABAP & Fiori com ${i} ano${i!==1?"s":""} e ${s} mês${s!==1?"es":""} de experiência prática em ambientes SAP ECC e S/4HANA. Histórico comprovado em AMS, projetos de melhoria e ciclos completos de implementação — do levantamento de requisitos ao suporte pós go-live.`);this.byId("_IDGenText3").setText(`• Atuação em projetos como Cockpit de Conciliação Contábil e extratores de migração de sistemas\n• Desenvolvimento ABAP com ALV, Smartforms (PDFs), ABAP OO, Module Pool, SAPScript\n• Criação de visões e clusters de atualização\n• Criação de queries via Eclipse\n• Implementação de BAPIs, BADIs, BTEs, User Exits, Enhancements e Proxy PI\n• SELECTs avançados com joins e análise de performance de programas\n• Criação de CDS Views e Apps Fiori consumindo CDS\n• Fiorização de transações padrão para Apps Fiori\n• Conhecimento das tabelas: FI, SD, MM, PP, EWM e Guepardo Tax\n• Debug e ajustes em processos padrão SAP\n• Desenvolvimento de aplicativos Fiori Freestyle e Fiori Elements`);this.byId("_IDGenText5").setText(`Data de Nascimento:  21.11.2005\n────────────────────────────────────────────────────────────────────\nCidadania:           Brasileiro\n────────────────────────────────────────────────────────────────────\nResidência:          Pomerode – SC, Brasil\n────────────────────────────────────────────────────────────────────\nMobilidade:          Nacional e Internacional\n────────────────────────────────────────────────────────────────────\nEstado Civil:        Solteiro\n────────────────────────────────────────────────────────────────────\nIdiomas:             Português – Nativo | Inglês – Intermediário B2 (cursando até C2)\n────────────────────────────────────────────────────────────────────`);this.byId("_IDGenLabel1").setText("Experiência Profissional – Sumário");this.byId("_IDGenLabel2").setText("Experiência em Projetos SAP – Detalhes");this.byId("_IDGenText1").setText(`Atuação em todas as fases do projeto: levantamento, análise, desenvolvimento, testes funcionais e homologação.\n\n• Glatz – Consultoria atual\n• DFSpro IT Solutions\n• Empresas atendidas: Kyly, Usina Coruripe, Sotreq, Unimed, Destro, Agrícola Alvorada, Grupo Bom Jesus, Arke, entre outras\n• Desenvolvimento técnico ABAP e integração de sistemas SAP\n• Participação ativa na entrega de especificações técnicas, testes, melhorias e suporte técnico pós go-live`);this.byId("_IDGenText4").setText(`Empresa:          Sotreq\n────────────────────────────────────────────────────────────────────\nDuração:           8 meses\n────────────────────────────────────────────────────────────────────\nRamo de Atuação:   Máquinas e Equipamentos Caterpillar\n────────────────────────────────────────────────────────────────────\nProjeto:           Cockpit de Conciliação Contábil\n────────────────────────────────────────────────────────────────────\nFunção:            Consultor SAP ABAP\n────────────────────────────────────────────────────────────────────\n\nImplementação de solução para análise, conciliação e compensação de contas contábeis — identificando divergências nos processos e realizando ajustes individualizados para a devida compensação das contas.\n\n\nEmpresa:          Kyly\n────────────────────────────────────────────────────────────────────\nDuração:           Em andamento (atual)\n────────────────────────────────────────────────────────────────────\nRamo de Atuação:   Têxtil\n────────────────────────────────────────────────────────────────────\nProjeto:           Implementação SAP S/4HANA\n────────────────────────────────────────────────────────────────────\nFunção:            Consultor SAP ABAP/Fiori\n────────────────────────────────────────────────────────────────────\n\nParticipação ativa no projeto de implementação do SAP S/4HANA com foco no desenvolvimento de aplicativos Fiori (Freestyle e Elements) e na personalização de processos padrão por meio de enhancements e adaptações ABAP.`);this.byId("_IDGenText8").setText(`• Ensino Médio – Concluído\n• Análise e Desenvolvimento de Sistemas – Em andamento (Ensino Superior)\n• Cursos e treinamentos SAP: ABAP, CDS Views, Fiori, SAP CAP, S/4HANA`)}}})});
